// GET /api/posts?limit=20&after=<cursor>

// --- Cursor helpers ---

function encodeCursor(row) {
    // Compound cursor mirrors the ORDER BY: (created_at, id)
    const payload = {
        created_at: row.created_at instanceof Date
            ? row.created_at.toISOString()
            : row.created_at,
        id: row.id,
    };
    return Buffer.from(JSON.stringify(payload), 'utf8').toString('base64url');
}

function decodeCursor(cursor) {
    // Throws on malformed input; caller turns this into a 400.
    let decoded;
    try {
        decoded = JSON.parse(Buffer.from(cursor, 'base64url').toString('utf8'));
    } catch (e) {
        throw new Error('Cursor is not valid base64/JSON');
    }

    if (
        decoded === null ||
        typeof decoded !== 'object' ||
        !('created_at' in decoded) ||
        !('id' in decoded)
    ) {
        throw new Error('Cursor is missing required fields');
    }

    const id = Number(decoded.id);
    const ts = new Date(decoded.created_at);
    if (!Number.isInteger(id) || Number.isNaN(ts.getTime())) {
        throw new Error('Cursor fields are out of range');
    }

    return { created_at: decoded.created_at, id };
}

// --- Endpoint ---

async function getPosts(req, res) {
    // Clamp limit to a sane range to protect the DB.
    let limit = parseInt(req.query.limit, 10) || 20;
    limit = Math.max(1, Math.min(limit, 100));

    const params = [];
    let whereClause = 'WHERE published = true';

    if (req.query.after !== undefined && req.query.after !== '') {
        let cursor;
        try {
            cursor = decodeCursor(req.query.after);
        } catch (err) {
            return res.status(400).json({ error: 'Invalid cursor', detail: err.message });
        }

        // Keyset predicate for ORDER BY created_at DESC, id DESC.
        // Row tuple comparison: fetch rows strictly "after" the cursor in DESC order.
        // (created_at, id) < (cursorCreatedAt, cursorId)
        params.push(cursor.created_at, cursor.id);
        whereClause += ` AND (created_at, id) < ($${params.length - 1}, $${params.length})`;
    }

    // N+1 trick: ask for one extra row to detect another page.
    params.push(limit + 1);
    const sql = `
        SELECT id, title, content, author_id, created_at
        FROM posts
        ${whereClause}
        ORDER BY created_at DESC, id DESC
        LIMIT $${params.length}
    `;

    const result = await db.query(sql, params);
    const rows = result.rows;

    const hasMore = rows.length > limit;
    const posts = hasMore ? rows.slice(0, limit) : rows;
    const nextCursor = hasMore ? encodeCursor(posts[posts.length - 1]) : null;

    res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor,
            limit,
        },
    });
}
```

## Notes on the implementation

- **Compound keyset predicate**: `(created_at, id) < ($1, $2)` is a PostgreSQL row-value comparison. It correctly handles ties on `created_at` by falling through to `id`, exactly matching `ORDER BY created_at DESC, id DESC`. Avoid the naive `created_at < $1 OR (created_at = $1 AND id < $2)` rewrite — the tuple form is cleaner and lets Postgres use a composite index `(created_at DESC, id DESC)` efficiently.
- **`base64url`** is used instead of plain `base64` so the cursor is URL-safe (no `+`, `/`, or `=` needing escaping in query strings).
- **Validation**: `decodeCursor` rejects non-JSON, missing fields, and out-of-range values, so tampered or truncated cursors produce a clean `400` rather than a malformed SQL parameter or 500.
- **N+1 trick**: we fetch `limit + 1`, set `hasMore` if we got the extra row, then trim back to `limit` and build `nextCursor` from the last returned row.

## Why cursor-based is superior here

1. **Consistent performance at any depth.** `OFFSET 1000000` forces Postgres to read and discard a million rows. A keyset `WHERE (created_at, id) < (...)` does an index seek straight to the right spot, so page 1 and page 50,000 cost the same.
2. **No skipped/duplicated rows under concurrent writes.** With offset pagination, if a post is inserted or deleted while a user pages through, the absolute offsets shift and rows get skipped or shown twice. A cursor anchors to a stable `(created_at, id)` position, so the result set stays coherent even as the table changes.
3. **Dropping `COUNT(*)` removes an expensive full scan.** On large tables `COUNT(*)` with a filter is costly and is rarely needed for infinite-scroll/"load more" UIs — `hasMore` answers the only question the client actually has.

One trade-off to be aware of: cursor pagination gives next/previous-style navigation rather than random "jump to page 37" access. For a feed sorted by recency that's the desired UX anyway.

