// ─── Cursor Helpers ──────────────────────────────────────────────────────────

/**
 * Encodes a (created_at, id) pair into an opaque base64 cursor string.
 * created_at is serialised as an ISO-8601 string so it round-trips through
 * JSON safely regardless of whether pg returns a Date object or a string.
 */
function encodeCursor(createdAt, id) {
    const payload = JSON.stringify({
        created_at: createdAt instanceof Date ? createdAt.toISOString() : createdAt,
        id,
    });
    return Buffer.from(payload).toString('base64url'); // URL-safe, no padding issues
}

/**
 * Decodes a cursor string back into { created_at, id }.
 * Returns null if the cursor is missing, malformed, or has unexpected shape.
 */
function decodeCursor(cursor) {
    try {
        const json = Buffer.from(cursor, 'base64url').toString('utf8');
        const parsed = JSON.parse(json);

        // Validate expected shape before trusting any values.
        if (
            typeof parsed !== 'object' ||
            parsed === null ||
            typeof parsed.created_at !== 'string' ||
            !parsed.created_at ||
            (typeof parsed.id !== 'number' && typeof parsed.id !== 'string')
        ) {
            return null;
        }

        // Ensure created_at is actually a valid timestamp.
        if (isNaN(new Date(parsed.created_at).getTime())) {
            return null;
        }

        return { created_at: parsed.created_at, id: parsed.id };
    } catch {
        // JSON.parse failure, base64 failure, etc.
        return null;
    }
}

// ─── Endpoint ────────────────────────────────────────────────────────────────

// GET /api/posts?limit=20&after=<cursor>
async function getPosts(req, res) {
    // Clamp limit to a safe maximum so clients can't request 10 000 rows.
    const limit = Math.min(Math.max(parseInt(req.query.limit) || 20, 1), 100);
    const afterCursor = req.query.after ?? null;

    // ── Decode & validate cursor ────────────────────────────────────────────
    let cursorData = null;
    if (afterCursor !== null) {
        cursorData = decodeCursor(afterCursor);
        if (!cursorData) {
            return res.status(400).json({
                error: 'Invalid cursor. Use the nextCursor value returned by a previous request.',
            });
        }
    }

    // ── Fetch limit + 1 rows ────────────────────────────────────────────────
    // PostgreSQL tuple comparison: (created_at, id) < ($1, $2) expands to
    //   created_at < $1  OR  (created_at = $1 AND id < $2)
    // which is exactly what "comes after this position in DESC, DESC order" means.
    // No OFFSET anywhere — the index on (created_at DESC, id DESC) seeks directly.
    let result;

    if (cursorData) {
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
                AND (created_at, id) < ($1::timestamptz, $2)
              ORDER BY created_at DESC, id DESC
              LIMIT $3`,
            [cursorData.created_at, cursorData.id, limit + 1]
        );
    } else {
        // First page — no cursor filter at all.
        result = await db.query(
            `SELECT id, title, content, author_id, created_at
               FROM posts
              WHERE published = true
              ORDER BY created_at DESC, id DESC
              LIMIT $1`,
            [limit + 1]
        );
    }

    // ── Apply N+1 trick ─────────────────────────────────────────────────────
    const rows    = result.rows;
    const hasMore = rows.length > limit;
    const posts   = hasMore ? rows.slice(0, limit) : rows; // drop the sentinel row

    // Build the next cursor from the last row we're actually returning.
    const nextCursor = hasMore
        ? encodeCursor(posts[posts.length - 1].created_at, posts[posts.length - 1].id)
        : null;

    // ── Respond ─────────────────────────────────────────────────────────────
    return res.json({
        posts,
        pagination: {
            hasMore,
            nextCursor, // null when this is the final page
            limit,
        },
    });
}
```

---

## How it works end-to-end

### First request
```
GET /api/posts?limit=20
```
No `after` param → no WHERE filter on the cursor → returns the 20 newest posts, plus a `nextCursor` if there are more.

### Subsequent requests
```
GET /api/posts?limit=20&after=eyJjcmVhdGVkX2F0IjoiMjAyNC0wMS0xNVQxMjo…
```
The cursor decodes to `{ created_at: "2024-01-15T12:34:56.789Z", id: 1042 }`.
PostgreSQL evaluates:
```sql
WHERE published = true
  AND (created_at, id) < ('2024-01-15T12:34:56.789Z'::timestamptz, 1042)
```
which is equivalent to:
```sql
WHERE published = true
  AND (
      created_at < '2024-01-15T12:34:56.789Z'
   OR (created_at = '2024-01-15T12:34:56.789Z' AND id < 1042)
  )
```
The index on `(created_at DESC, id DESC)` seeks directly to that position — no rows are scanned and discarded.

### Final page
```json
{
    "posts": [...],
    "pagination": {
        "hasMore": false,
        "nextCursor": null,
        "limit": 20
    }
}
```

---

## Why cursor-based pagination is superior here

| Problem | Offset pagination | Cursor pagination |
|---|---|---|
| **Performance at depth** | `OFFSET 10000` forces PostgreSQL to read and discard 10 000 rows even with an index | Seeks directly to the cursor position via the index — O(log n), not O(n) |
| **Expensive COUNT** | Requires a full index scan to report `totalPages` | Eliminated entirely; `hasMore` costs nothing |
| **Data shifts mid-scroll** | A new post inserted between page 1 and page 2 causes the user to see a duplicate or skip an item on the next `OFFSET` | Cursor points to a specific row; new inserts don't disturb already-seen positions |
| **Live/real-time feeds** | Breaks badly as rows are added or deleted constantly | Stable by design — each page is "everything after row X" |

The compound `(created_at, id)` cursor is important: `created_at` alone isn't unique (two posts can share a timestamp), so `id` serves as a tiebreaker, guaranteeing the cursor identifies exactly one position in the ordered set and no rows are ever skipped or repeated.

